svg.script:

document.addEventListener("DOMContentLoaded", function() {
    let db;
    const req = indexedDB.open("CloudBridgeDB", 1);
    req.onupgradeneeded = e => e.target.result.createObjectStore("store");
    req.onsuccess = e => {
        db = e.target.result;
        if (window.parent) window.parent.postMessage({ status: "bridge_ready" }, "*");
    };

    window.addEventListener("message", async function(event) {
        const data = event.data;
        if (!db || !data || !data.action) return;

        const res = (action, success, payload = {}) => {
            event.source.postMessage({ status: success ? "success" : "error", action, key: data.key, ...payload }, event.origin);
        };

        try {
            if (data.action === "write") {
                const tx = db.transaction("store", "readwrite");
                tx.objectStore("store").put(data.value, data.key);
                tx.oncomplete = () => res("write", true);
                tx.onerror = () => res("write", false, { message: tx.error.message });
            }
            if (data.action === "read") {
                const tx = db.transaction("store", "readonly");
                const getReq = tx.objectStore("store").get(data.key);
                getReq.onsuccess = () => event.source.postMessage({ status: "read_result", key: data.key, value: getReq.result }, event.origin);
                getReq.onerror = () => res("read", false, { message: getReq.error.message });
            }
        } catch (e) {
            res(data.action, false, { message: e.message });
        }
    });
});
